# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

public async Task PurchaseTickets(int eventId, int purchaseQuantity)
{
    using (var context = new EventBookingContext())
    {
        var eventDetails = await context.Events
            .Include(e => e.Tickets)
            .FirstOrDefaultAsync(e => e.EventId == eventId);

        if (eventDetails == null)
        {
            throw new Exception("Event not found");
        }

        int availableSeats = eventDetails.AvailableSeats;
        int remainingSeats = availableSeats - purchaseQuantity;

        if (remainingSeats < 0)
        {
            throw new Exception("Not enough seats available");
        }

        eventDetails.AvailableSeats = remainingSeats;

        context.Entry(eventDetails).Property(e => e.AvailableSeats).IsModified = true;

        await context.SaveChangesAsync();
    }
}